let message = "⚠️ *Claims in 'Created' Stage but (Inactive > 7 Days) and Assigned*\n\n";

// Loop through all results from MySQL
const list = $input.all().map(item => {
    const claimId = item.json["Claim ID"];
    const emp_name = item.json["Claimaint Name"];
    const corp_name = item.json["Claimaint Corporate"];
    const url = `https://thor.smartchoice.pk/opd/claim/detail/${claimId}`;
    const diff_bw_lst__mdf = item.json["Difference B/W Last modified till Now"];

    return `• *Claim #${claimId} - <${url}|View Details>\n (${emp_name}) - (${corp_name})\n Last Modified: ${diff_bw_lst__mdf} Days Before`;
}).join('\n\n');

return {
  formattedText: message + list
};

